    var cvResults = mlContext.BinaryClassification.CrossValidate(dataView, pipeline, numberOfFolds: 2, labelColumnName: nameof(ChurnInput.Churned));
    Console.WriteLine($"Model trained (cross-validation, {rowCount} rows) — Avg Accuracy: {cvResults.Average(r => r.Metrics.Accuracy):F4}");
    model = pipeline.Fit(dataView);
