3. using Microsoft.Extensions.ML;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. 
7. // Train the model at startup and register PredictionEnginePool
8. var mlContext = new MLContext(seed: 42);
9. var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
10. var dataView = mlContext.Data.LoadFromTextFile<ChurnInput>(dataPath, hasHeader: true, separatorChar: ',');
11. 
12. // Map "Yes"/"No" to boolean label
13. var labelMapping = new Dictionary<string, bool> { { "Yes", true }, { "No", false } };
14. var pipeline = mlContext.Transforms.Conversion.MapValue(
15.         "Label", labelMapping, inputColumnName: "Churned")
16.     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region)))
17.     .Append(mlContext.Transforms.Concatenate("Features", nameof(ChurnInput.Age), nameof(ChurnInput.Income), nameof(ChurnInput.PurchaseHistory), "RegionEncoded"))
18.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
19.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
20.         labelColumnName: "Label", featureColumnName: "Features"));
21. 
22. // Use cross-validation for small datasets; train/test split when enough data exists
23. ITransformer model;
24. var dataEnum = mlContext.Data.CreateEnumerable<ChurnInput>(dataView, reuseRowObject: false);
25. var rowCount = dataEnum.Count();
26. if (rowCount >= 50)
27. {
28.     var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
29.     model = pipeline.Fit(split.TrainSet);
30.     var predictions = model.Transform(split.TestSet);
31.     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
32.     Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
33. }
34. else
35. {
36.     // Dataset too small for reliable evaluation — train on all data
37.     model = pipeline.Fit(dataView);
38.     Console.WriteLine($"Model trained on {rowCount} rows (add more data for evaluation metrics).");
39. }
40. 
41. // Save model and register pooled prediction engine
42. var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");
43. mlContext.Model.Save(model, dataView.Schema, modelPath);
44. 
45. builder.Services.AddPredictionEnginePool<ChurnInput, ChurnOutput>()
